import{_ as i}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as a,c as e,g as r,a as n,f as p}from"./app.16aa4dd9.js";const d="/imgs/construction.jpg",l={},t=n("p",null,"这是摘要",-1),o=p('<h1 id="spring" tabindex="-1"><a class="header-anchor" href="#spring" aria-hidden="true">#</a> Spring</h1><h2 id="初识spring" tabindex="-1"><a class="header-anchor" href="#初识spring" aria-hidden="true">#</a> 初识Spring</h2><h3 id="什么是spring" tabindex="-1"><a class="header-anchor" href="#什么是spring" aria-hidden="true">#</a> 什么是Spring?</h3><p>分层的Java EE应用full-stack轻量级开源框架,以IOC和AOP为内核</p><p>IOC (Inverse Of Control:反转控制) AOP (Aspect Oriented Programming:面向切面编程)</p><p>提供了展现层 SpringMVC和持久层 Spring JDBCTemplate 以及业务层事务管理等,整合了许多著名第三方框架.</p><h3 id="发展历程" tabindex="-1"><a class="header-anchor" href="#发展历程" aria-hidden="true">#</a> 发展历程</h3><p>EJB1.0 EJB1.0 EJB1.0 EJB1.0 EJB1.0 EJB1.0</p><h3 id="优势是什么" tabindex="-1"><a class="header-anchor" href="#优势是什么" aria-hidden="true">#</a> 优势是什么?</h3><ul><li><p>方便解耦，简化开发 通过Spring提供的IoC容器，我们可以将对象之间的依赖关系交由Spring进行控制，避免硬编码所 造成的过度程序耦合。有了Spring，用户不必再为单实例模式类、属性文件解析等这些很底层的需 求编写代码，可以更专注于上层的应用。</p></li><li><p>AOP编程的支持 通过Spring提供的AOP功能，方便进行面向切面的编程，许多不容易用传统OOP实现的功能可以通过 AOP轻松应付。</p></li><li><p>声明事物的支持 在Spring中，我们可以从单调烦闷的事务管理代码中解脱出来，通过声明式方式灵活地进行事务的 管理，提高开发效率和质量。</p></li><li><p>方便程序的测试 可以用非容器依赖的编程方式进行几乎所有的测试工作，在Spring里，测试不再是昂贵的操作， 而是随手可做的事情。例如：Spring对Junit4支持，可以通过注解方便的测试Spring程序。</p></li><li><p>方便集成各种优秀框架 Spring不排斥各种优秀的开源框架，相反，Spring可以降低各种框架的使用难度，Spring提供了 对各种优秀框架（如Struts,Hibernate、Hessian、Quartz）等的直接支持。</p></li><li><p>降低Java EE API的使用难度 Spring对很多难用的Java EE API（如JDBC，JavaMail，远程调用等）提供了一个薄薄的封装层， 通过Spring的简易封装，这些Java EE API的使用难度大为降低。</p></li><li><p>Java 源码是经典学习范例 Spring的源码设计精妙、结构清晰、匠心独用，处处体现着大师对Java设计模式灵活运用以及对 Java技术的高深造诣。Spring框架源码无疑是Java技术的最佳实践范例。如果想在短时间内迅速 提高自己的Java技术水平和应用开发水平，学习和研究Spring源码将会使你收到意想不到的效果。</p></li></ul><h3 id="体系结构" tabindex="-1"><a class="header-anchor" href="#体系结构" aria-hidden="true">#</a> 体系结构</h3><div style="text-align:center;"><p><img src="'+d+'" alt="construction"></p></div><h3 id="spring快速入门" tabindex="-1"><a class="header-anchor" href="#spring快速入门" aria-hidden="true">#</a> Spring快速入门</h3><h3 id="开发步骤" tabindex="-1"><a class="header-anchor" href="#开发步骤" aria-hidden="true">#</a> 开发步骤</h3><p>创建对象时,通过<code>getbean(id)</code>方法获取所需的对象, <code>getbean(id)</code>通过读取<code>XML</code>文件以及id来获得对象的全名,返回对应对象来完成对象创建.<code>XML</code>配置文件中的内容指向目的对象类.</p><p>解耦就是改变类时无序更改全部代码,只需更改<code>XML</code>中配置文件指向内容即可.</p><ol><li>导入Spring开发基本包坐标</li><li>编写Dao接口和实现类</li><li>创建Spring核心配置文件</li><li>在Spring配置文件中配置<code>UserDaompl</code></li><li>使用Spring的API获得Bean实例</li></ol><p>简化后就是:</p><ol><li>导入坐标</li><li>创建Bean</li><li>创建<code>applicationContext.xml</code></li><li>在配置文件中进行配置</li><li>创建<code>ApplicationContext</code>对象<code>geiBean</code></li></ol><h3 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h3>',20);function c(h,s){return a(),e("div",null,[t,r(" more "),o])}const u=i(l,[["render",c],["__file","Spring.html.vue"]]);export{u as default};
